168→    private var onEditCardActivityResult = registerForActivityResult(StartActivityForResult()) { result: ActivityResult ->
169→        Timber.d("onEditCardActivityResult: resultCode=%d", result.resultCode)
170→        if (result.resultCode == DeckPicker.RESULT_DB_ERROR) {
171→            closeCardBrowser(DeckPicker.RESULT_DB_ERROR)
172→        }
173→        if (result.resultCode != RESULT_CANCELED) {
174→            Timber.i("CardBrowser:: CardBrowser: Saving card...")
175→            launchCatchingTask { saveEditedCard() }
176→        }
177→        val data = result.data
178→        if (data != null &&
179→            (data.getBooleanExtra(NoteEditor.RELOAD_REQUIRED_EXTRA_KEY, false) || data.getBooleanExtra(NoteEditor.NOTE_CHANGED_EXTRA_KEY, false))
180→        ) {
181→            Timber.d("Reloading Card Browser due to activity result")
182→            // if reloadRequired or noteChanged flag was sent from note editor then reload card list
183→            mShouldRestoreScroll = true
184→            searchCards()
185→            // in use by reviewer?
186→            if (reviewerCardId == mCurrentCardId) {
187→                mReloadRequired = true
188→            }
189→        }
190→        invalidateOptionsMenu() // maybe the availability of undo changed
191→    }
192→    private var onAddNoteActivityResult = registerForActivityResult(StartActivityForResult()) { result: ActivityResult ->
193→        Timber.d("onAddNoteActivityResult: resultCode=%d", result.resultCode)
194→        if (result.resultCode == DeckPicker.RESULT_DB_ERROR) {
195→            closeCardBrowser(DeckPicker.RESULT_DB_ERROR)
