1473→    @RustCleanup("remove card cache; switch to RecyclerView and browserRowForId (#11889)")
1474→    @VisibleForTesting
1475→    fun searchCards() {
1476→        // cancel the previous search & render tasks if still running
1477→        invalidate()
1478→        if ("" != mSearchTerms && mSearchView != null) {
1479→            mSearchView!!.setQuery(mSearchTerms, false)
1480→            mSearchItem!!.expandActionView()
1481→        }
1482→        val searchText: String? = if (mSearchTerms.contains("deck:")) {
1483→            "($mSearchTerms)"
1484→        } else {
1485→            if ("" != mSearchTerms) "$mRestrictOnDeck($mSearchTerms)" else mRestrictOnDeck
1486→        }
1487→        // clear the existing card list
1488→        mCards.reset()
1489→        cardsAdapter.notifyDataSetChanged()
1490→        val query = searchText!!
1491→        val order = mOrder.toSortOrder()
1492→        launchCatchingTask {
1493→            Timber.d("performing search")
1494→            val cards = withProgress { searchForCards(query, order, cardsOrNotes) }
1495→            Timber.d("Search returned %d cards", cards.size)
1496→            // Render the first few items
1497→            for (i in 0 until Math.min(numCardsToRender(), cards.size)) {
1498→                cards[i].load(false, mColumn1Index, mColumn2Index)
1499→            }
1500→            redrawAfterSearch(cards)
1501→        }
1502→    }
