    }","new_string":"    @RustCleanup("Remove in V16.") // Not in libAnki
    fun findOneCardByNote(
        query: String,
        order: SortOrder = SortOrder.NoOrdering()
    ): List<CardId> {
        // This function shouldn't exist and CardBrowser should be modified to use Notes,
        // so not much effort was expended here.
        //
        // When used by CardBrowser's "Notes" mode, it is expected to honor the provided sort order.

        val noteIds = findNotes(query, order)
        if (noteIds.isEmpty()) {
            return emptyList()
        }

        // Select the card with the lowest `ord` to show, while preserving the note ordering.
        val wantedValues = noteIds.indices.joinToString(",") { "(?,?)" }
        val bindArgs = ArrayList<Any>(noteIds.size * 2)
        noteIds.forEachIndexed { idx, nid ->
            bindArgs.add(nid)
            bindArgs.add(idx)
        }

        return db.queryLongList(
            """
WITH wanted(nid, pos) AS (VALUES $wantedValues),
card_with_min_ord AS (
  SELECT nid, MIN(ord) AS ord
  FROM cards
  WHERE nid IN (SELECT nid FROM wanted)
  GROUP BY nid
)
SELECT c.id
FROM wanted
JOIN card_with_min_ord ON wanted.nid = card_with_min_ord.nid
JOIN cards AS c ON card_with_min_ord.nid = c.nid AND card_with_min_ord.ord = c.ord
ORDER BY wanted.pos;
            """.trimIndent(),
            *bindArgs.toTypedArray()
        )
    }"}

